content:
tml! {
	@input({ user:User, onUpdate: Function })
	<div class="avatar">
		<img src={user.avatar} alt={user.name} />
	</div>
}

tml! {
	@if(user.role === 'admin') {
		<div class="admin">
			<h1>Admin Dashboard</h1>
			@for(const item of user.items) {
				<Card item={item} />
			}
			@empty {
				<p>No items</p>
			}
		</div>
	}
	@else {
		<SignIn />
	}
}

tml! {
	<ul>
		@for(const [index, user] of users.entries()) {
			<li key={index}>
				<UserCard user={user} />
			</li>
		}
		@empty {
			<p>No users found.</p>
		}
	</ul>
}
